CREATE TABLE `wp_platform_contracts` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `request_id` bigint(20) unsigned NOT NULL,
  `expert_user_id` bigint(20) unsigned NOT NULL,
  `college_user_id` bigint(20) unsigned NOT NULL,
  `contract_pdf_id` bigint(20) unsigned DEFAULT NULL,
  `template_version` varchar(20) DEFAULT NULL,
  `accepted_at` datetime DEFAULT NULL,
  `ip` varchar(45) DEFAULT NULL,
  `status` varchar(50) DEFAULT 'generated',
  `total_amount` decimal(10,2) DEFAULT 0.00,
  `class_start_iso` varchar(30) DEFAULT NULL,
  `duration_minutes` int(11) DEFAULT 60,
  `sign_token` varchar(100) DEFAULT NULL,
  `sign_token_expires` datetime DEFAULT NULL,
  `signed_at` datetime DEFAULT NULL,
  `signed_by_user_id` bigint(20) DEFAULT NULL,
  `signed_name` varchar(255) DEFAULT NULL,
  `signed_ip` varchar(100) DEFAULT NULL,
  `pdf_path` text DEFAULT NULL,
  `order_id` bigint(20) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_request` (`request_id`),
  KEY `request_id` (`request_id`),
  KEY `sign_token` (`sign_token`)
) ENGINE=InnoDB AUTO_INCREMENT=111 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
